import axios from "axios";

// Create Axios instance
const api = axios.create({
  baseURL: "http://localhost:8080/api", // your backend
  headers: {
    "Content-Type": "application/json",
  },
});

// ✅ Attach token automatically to all requests
api.interceptors.request.use((config) => {
  const token = localStorage.getItem("token") || sessionStorage.getItem("token");
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Auth APIs
const login = async (email, password) => {
  try {
    const response = await api.post("/auth/login", { email, password });
    return response; // response.data contains { token, email }
  } catch (error) {
    console.error("API login error:", error);
    throw error;
  }
};

const signup = async (email, password) => {
  try {
    const response = await api.post("/auth/signup", { email, password });
    return response; // response.data contains user object
  } catch (error) {
    console.error("API signup error:", error);
    throw error;
  }
};

// Vehicles APIs
const getVehicles = async () => {
  const response = await api.get("/vehicles");
  return response.data;
};

const addVehicle = async (vehicle) => {
  const response = await api.post("/vehicles", vehicle);
  return response.data;
};

// Routes APIs
const optimizeRoute = async (routeRequest) => {
  const response = await api.post("/routes/optimize", routeRequest);
  return response.data;
};

// Alerts APIs
const getAlerts = async () => {
  const response = await api.get("/alerts");
  return response.data;
};

export default {
  login,
  signup,
  getVehicles,
  addVehicle,
  optimizeRoute,
  getAlerts,
};
